import React, { useState, useEffect } from 'react';
import { Package, Bike, CheckCircle2 } from 'lucide-react';

const SeguimientoPedido = ({ pedido, onFinalizar }) => {
  const [fase, setFase] = useState(1); 
  const [progreso, setProgreso] = useState(0);
  const [horaLlegada, setHoraLlegada] = useState("");

  useEffect(() => {
    // Calcular hora real de llegada (Hora actual + 30 min)
    const ahora = new Date();
    ahora.setMinutes(ahora.getMinutes() + 30);
    const horaFormateada = ahora.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const horaFinFormateada = new Date(ahora.getTime() + 15 * 60000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    setHoraLlegada(`${horaFormateada} - ${horaFinFormateada}`);

    const tiempoFase1 = 8000; // 8s Preparación
    const tiempoFase2 = 10000; // 10s Envío
    const intervaloMs = 100;

    const timer = setInterval(() => {
      setProgreso((prev) => {
        if (fase === 1) {
          if (prev >= 100) { setFase(2); return 0; }
          return prev + (100 / (tiempoFase1 / intervaloMs));
        } else if (fase === 2) {
          if (prev >= 100) { setFase(3); clearInterval(timer); return 100; }
          return prev + (100 / (tiempoFase2 / intervaloMs));
        }
        return 100;
      });
    }, intervaloMs);

    if (fase === 3) {
      const finalTimeout = setTimeout(() => { if (onFinalizar) onFinalizar(pedido.id); }, 4000);
      return () => clearTimeout(finalTimeout);
    }
    return () => clearInterval(timer);
  }, [fase, pedido.id, onFinalizar]);

  return (
    <div style={card}>
      <div style={header}>
        <div style={infoEntrega}>
          <span style={textChico}>Llegada estimada</span>
          <div style={badgeEnHora}>EN HORA</div>
          <h2 style={horaEstilo}>{fase === 3 ? "¡ENTREGADO!" : horaLlegada}</h2>
        </div>
        {/* Recuperamos tus iconos en el lateral */}
        <div style={cajaIcono}>
          {fase === 1 && <Package size={32} color="white" />}
          {fase === 2 && <Bike size={32} color="white" className="animar-moto" />}
          {fase === 3 && <CheckCircle2 size={32} color="white" />}
        </div>
      </div>

      {/* Barra segmentada estilo PedidosYa pero integrada */}
      <div style={contenedorBarra}>
        {[1, 2, 3, 4].map((seg) => {
          let llenado = 0;
          if (fase === 1) {
            if (seg === 1) llenado = Math.min(progreso * 2, 100);
            if (seg === 2) llenado = progreso > 50 ? (progreso - 50) * 2 : 0;
          } else if (fase >= 2) {
            if (seg <= 2) llenado = 100;
            if (seg === 3) llenado = fase === 3 ? 100 : Math.min(progreso * 2, 100);
            if (seg === 4) llenado = fase === 3 ? 100 : (progreso > 50 ? (progreso - 50) * 2 : 0);
          }
          return (
            <div key={seg} style={segmentoGris}>
              <div style={{ ...segmentoColor, width: `${llenado}%` }} />
            </div>
          );
        })}
      </div>

      <div style={estadoContenedor}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          {fase === 2 && <Bike size={18} color="#e67e22" />}
          <span style={textoEstado}>
            {fase === 1 && "El local está preparando tu pedido"}
            {fase === 2 && "La Scaloneta está llevando tu pedido"}
            {fase === 3 && "¡Pedido entregado! Que lo disfrutes"}
          </span>
        </div>
      </div>
    </div>
  );
};

// --- ESTILOS ADAPTADOS ---
const card = { background: 'white', padding: '20px', borderRadius: '16px', boxShadow: '0 8px 30px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9', marginBottom: '20px' };
const header = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const infoEntrega = { display: 'flex', flexDirection: 'column' };
const textChico = { fontSize: '12px', color: '#64748b', fontWeight: '600' };
const badgeEnHora = { background: '#27ae60', color: 'white', padding: '2px 8px', borderRadius: '4px', fontSize: '10px', fontWeight: 'bold', width: 'fit-content', margin: '4px 0' };
const horaEstilo = { margin: 0, fontSize: '24px', fontWeight: '800', color: '#1e293b' };
const cajaIcono = { background: '#e67e22', width: '55px', height: '55px', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 12px rgba(230, 126, 34, 0.3)' };
const contenedorBarra = { display: 'flex', gap: '8px', marginBottom: '20px' };
const segmentoGris = { flex: 1, height: '6px', background: '#f1f5f9', borderRadius: '10px', overflow: 'hidden' };
const segmentoColor = { height: '100%', background: '#e67e22', transition: 'width 0.1s linear' };
const estadoContenedor = { borderTop: '1px solid #f1f5f9', paddingTop: '15px' };
const textoEstado = { fontSize: '14px', fontWeight: '700', color: '#1e293b' };

export default SeguimientoPedido;
